import{_ as n,o as s,c as l,O as i}from"./chunks/framework.1e3ff9a3.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"SmartFlow","text":"智流·智能执行平台","tagline":"面向多租户治理、可信执行、本地桥接与私有化交付的企业级业务自动化平台。先用免费体验与团队演示承接入口，再逐步走向标准产品、CLI 协同和企业部署。","actions":[{"theme":"brand","text":"申请免费试用","link":"/contact#lead-form"},{"theme":"alt","text":"预约团队版演示","link":"/contact#lead-form"},{"theme":"alt","text":"产品概览","link":"/product/"},{"theme":"alt","text":"CLI 指引","link":"/product/cli"},{"theme":"alt","text":"部署方式","link":"/product/deployment"}]},"features":[{"title":"多租户治理","details":"public 总控、客户租户隔离、模板分发、台账与审计已经具备平台化边界。"},{"title":"可信执行闭环","details":"从计划生成、人工确认到执行留痕，重点始终是可控、可确认、可追踪。"},{"title":"本地与云端协同","details":"Web 控制面、CLI、本地执行和未来 Agent 按同一套治理逻辑持续收敛。"},{"title":"1.0 到 4.0","details":"从可信交付版、标准产品化，到生态开放与智能执行基础设施，路线已经明确。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1775707265000}'),e={name:"index.md"};function c(t,a,r,d,p,o){return s(),l("div",null,a[0]||(a[0]=[i('<div class="landing-shell"><section class="landing-band landing-band--brand landing-band--brand-story"><div class="landing-brand"><div class="landing-brand__copy"><p class="landing-kicker">Brand Signal</p><h2>首页先承接转化，再解释平台能力</h2><p class="landing-lead"> “智流”对应的是 <strong>智能调度</strong>、<strong>经验资产化</strong> 和 <strong>安全可控执行</strong>。 这个首页不再把视觉主区只当作介绍位，而是明确承接 <strong>免费试用</strong>、<strong>团队演示</strong> 和 <strong>企业私有化咨询</strong> 三条转化路径。 </p><div class="landing-brand__chips"><span>申请试用</span><span>预约演示</span><span>智能调度</span><span>安全可控</span><span>Open &amp; Secure</span></div><div class="landing-brand__quick-grid"><article class="landing-brand__quick-card"><span>入口</span><strong>试用、演示、企业咨询</strong></article><article class="landing-brand__quick-card"><span>底座</span><strong>治理、执行、CLI、本地桥接</strong></article></div><p class="landing-lead"> 当前公开链路已经是 <strong>免登录体验页 -&gt; 注册 / 登录 -&gt; 试用 / 演示 / 咨询</strong> 的正式入口。 其中体验页访问统计当前按浏览器会话记录一次，不按唯一 IP 去重。 </p></div><div class="landing-brand__panel"><article class="landing-brand__signal-card"><div class="landing-brand__signal-head"><span>ENTRY SYSTEM</span><span>SYNC 01</span></div><p class="landing-brand__signal-summary">试用、演示、企业咨询统一承接，治理与执行走同一条可信路径。</p><div class="landing-brand__signal-list"><div class="landing-brand__signal-item"><strong>入口</strong><span>免费体验、团队演示、企业咨询</span></div><div class="landing-brand__signal-item"><strong>底座</strong><span>治理、执行、CLI、本地桥接</span></div></div><div class="landing-brand__signal-tags"><span>Unified Entry</span><span>Policy Inside</span></div></article></div></div></section><section class="landing-band landing-band--overview landing-band--overview-center"><div class="landing-section-head"><p class="landing-kicker">Platform Thesis</p><h2>把“会聊天”升级成“会在规则里执行”</h2><p class="landing-lead"><strong>SmartFlow AI Skill Platform</strong> 的项目层定位是 <strong>An Open &amp; Secure AI Agent Execution Layer</strong>。 落到产品层，它对外呈现为“智流·智能执行平台”。它真正想解决的，不是聊天体验，而是 <strong>真实任务如何在规则里被稳定执行</strong>。 </p></div><div class="landing-metrics"><article class="metric-card"><span class="metric-value">4</span><span class="metric-label">当前公开主线</span><p>企业交付、平台治理、个人入口、CLI / Agent。</p></article><article class="metric-card"><span class="metric-value">1</span><span class="metric-label">统一治理内核</span><p>权限、执行、审计、注册和分发都收敛到同一套逻辑。</p></article><article class="metric-card"><span class="metric-value">1.0→4.0</span><span class="metric-label">清晰演进路线</span><p>从可交付，到产品化，再到生态与智能执行基础设施。</p></article><article class="metric-card"><span class="metric-value">Cloud / Local / Edge</span><span class="metric-label">执行位置扩展</span><p>今天承接脚本与本地执行，未来延展到边缘节点和设备端。</p></article></div></section><section class="landing-band landing-band--commercial"><div class="landing-section-head"><p class="landing-kicker">Commercial Route</p><h2>官网直接服务三层商业路径</h2><p class="landing-lead"> 免费版先让价值被低门槛感知，团队版承接协作和标准订阅，企业版承接私有化与正式交付。 这不是三套分裂产品，而是一套平台的三种商业入口。 </p></div><div class="landing-grid landing-grid--three"><article class="mode-card"><span class="link-panel-label">Free</span><h3>免费版 / 社区技能</h3><p>面向开发者和个体用户，先体验平台价值、沉淀真实脚本样本，并为社区技能与生态入口蓄水。</p></article><article class="mode-card"><span class="link-panel-label">Team</span><h3>团队版 SaaS</h3><p>承接多人协作、共享技能、审批、权限控制和更稳定的标准化产品订阅，是当前最直接的增长主线。</p></article><article class="mode-card"><span class="link-panel-label">Enterprise</span><h3>企业版 / 私有化</h3><p>面向更重的安全、审计、内网、本地 Agent 和正式交付需求，用专业深度建立高端可信形象。</p></article></div><div class="landing-inline-links"><a href="./product/">查看免费版路径</a><a href="./contact.html#lead-form">申请免费试用</a><a href="./contact.html#lead-form">预约团队版演示</a><a href="./product/editions.html">查看版本路线</a></div></section><section class="landing-band"><div class="landing-section-head"><p class="landing-kicker">Identity</p><h2>项目名与产品名</h2><p class="landing-lead"> 文档同时使用项目名和产品名。前者表达平台的技术定位和长期演进方向，后者用于面向客户和用户的产品表达。 </p></div><div class="landing-grid landing-grid--two"><article class="mode-card"><span class="link-panel-label">Project</span><h3>SmartFlow AI Skill Platform</h3><p><strong>定位：</strong>An Open &amp; Secure AI Agent Execution Layer</p><p><strong>Slogan：</strong>Make AI Work, Make Work Smart.</p><p>用于表达平台的技术定位和长期方向，可理解为从 1.0 执行底座逐步走向 2.0 生态协同的项目名。</p></article><article class="mode-card"><span class="link-panel-label">Product</span><h3>智流·智能执行平台</h3><p><strong>副标题：</strong>企业级业务自动化与安全执行系统</p><p><strong>Slogan：</strong>复杂工作，简单对话；私有部署，安全省人。</p><p>一个用 AI 调度脚本的平台，复杂工作一句话搞定。</p></article></div></section><section id="founder-note" class="landing-band landing-band--overview landing-band--founder"><div class="landing-section-head"><p class="landing-kicker">Founder Note</p><h2>谁在构建智流，为什么这套平台值得继续聊</h2><p class="landing-lead"> 智流由一位拥有 <strong>10+ 年政企交付经验</strong> 的独立架构师持续打造。 当前项目已经不是概念稿，而是同时具备 <strong>多租户治理</strong>、<strong>可审计执行</strong>、 <strong>免费线索入口</strong> 和 <strong>CLI / 本地执行演进路径</strong> 的真实工程底座。 </p><div class="landing-inline-links"><a href="./contact.html#lead-form">继续沟通合作</a><a href="https://zmx2321.github.io/vite-blog" target="_blank" rel="noreferrer">查看公开博客</a></div></div><div class="landing-metrics"><article class="metric-card"><span class="metric-value">10+</span><span class="metric-label">年交付与架构视角</span><p>从脚本接入、权限、审计、部署到多租户治理，平台不是只做一个漂亮前台。</p></article><article class="metric-card"><span class="metric-value">public + tenant</span><span class="metric-label">治理边界先成立</span><p>平台总控、客户租户、模板分发、审计日志和台账已经形成正式边界。</p></article><article class="metric-card"><span class="metric-value">Web + CLI</span><span class="metric-label">执行端继续扩展</span><p>今天先打通网页控制面和本地接入，未来继续延展到 Agent、边缘节点和设备端。</p></article><article class="metric-card"><span class="metric-value">Free → Team → Enterprise</span><span class="metric-label">商业路径清晰</span><p>免费版承接入口，团队版承接订阅，企业版承接高价值交付，官网直接为这条路径服务。</p></article></div></section><section class="landing-band landing-band--flow"><div class="landing-section-head"><p class="landing-kicker">Execution Flow</p><h2>平台如何把任务变成可交付执行</h2></div><div class="landing-flow"><article class="flow-card"><span class="flow-index">01</span><h3>意图理解与计划生成</h3><p>先理解任务，再给出执行计划，而不是直接越权调用底层能力。</p></article><article class="flow-card"><span class="flow-index">02</span><h3>能力匹配与安全裁决</h3><p>把脚本、Skill、模板和后续能力包组织成正式目录，并受权限和规则控制。</p></article><article class="flow-card"><span class="flow-index">03</span><h3>人工确认与真实执行</h3><p>关键动作需要确认，执行端可以在云端、本地或未来的边缘节点。</p></article><article class="flow-card"><span class="flow-index">04</span><h3>结果回传与审计留痕</h3><p>从结果产出到日志和审计，平台强调可追踪，而不是一次性跑完就结束。</p></article></div></section><section class="landing-band landing-band--audience"><div class="landing-section-head"><p class="landing-kicker">Who It Fits</p><h2>它更适合这些角色</h2></div><div class="landing-grid landing-grid--three"><article class="landing-card"><h3>企业交付团队</h3><p>需要一个客户一个租户、一个交付入口、可持续扩展多客户，而不是把所有客户混在一个后台里。</p></article><article class="landing-card"><h3>平台运营方</h3><p>需要统一管理模板、公告、审计、客户台账和版本回滚，同时保持租户边界清晰。</p></article><article class="landing-card"><h3>开发者与小团队</h3><p>需要把已有脚本整理成可调用、可描述、可分享的能力，并保留本地执行路径。</p></article></div></section><section class="landing-band landing-band--modes"><div class="landing-section-head"><p class="landing-kicker">Deployment Modes</p><h2>同一套治理逻辑，覆盖不同部署形态</h2></div><div class="landing-grid landing-grid--two"><article class="mode-card"><h3>单租户交付</h3><p>面向企业客户交付，一个客户一个租户，一个入口，一套可持续维护的能力边界。</p></article><article class="mode-card"><h3>平台总控治理</h3><p>用 <code>public</code> 统一管理租户、模板、公告、日志和台账，但不打破隔离。</p></article><article class="mode-card"><h3>免费体验入口</h3><p>面向个人用户和小团队作为体验前台，承接增长样本和未来升级路径。</p></article><article class="mode-card"><h3>本地与边缘执行</h3><p>保留本地环境、CLI、未来 Agent 与边缘节点的执行空间，让控制面与执行端继续统一。</p></article></div><div class="landing-inline-links"><a href="./product/deployment.html">查看部署方式</a><a href="./product/scenarios.html">查看应用场景</a><a href="./product/cli.html">查看 CLI 指引</a></div></section><section class="landing-band landing-band--roadmap"><div class="landing-section-head"><p class="landing-kicker">Roadmap</p><h2>从 1.0 到 4.0，不只是加功能，而是平台角色变化</h2></div><div class="roadmap-grid"><article class="roadmap-card"><span class="roadmap-stage">1.0</span><h3>可信 AI 执行交付版</h3><p>先把客户交付、平台治理、免费入口和 CLI 最小闭环做稳。</p></article><article class="roadmap-card"><span class="roadmap-stage">2.0</span><h3>标准产品化版</h3><p>形成免费版、团队版、企业版的正式产品梯度和配额体系。</p></article><article class="roadmap-card"><span class="roadmap-stage">3.0</span><h3>生态开放版</h3><p>让第三方模板、技能、审核和分发开始进入正式平台生态。</p></article><article class="roadmap-card roadmap-card--accent"><span class="roadmap-stage">4.0</span><h3>智能执行基础设施版</h3><p>把脚本与 Skill 的治理逻辑继续扩展到插件包、边缘能力包和未来设备插件。</p></article></div><div class="landing-inline-links"><a href="./product/editions.html">查看完整版本路线</a></div></section><section class="landing-band landing-band--links"><div class="landing-grid landing-grid--three"><a class="link-panel" href="./guide/"><span class="link-panel-label">Guide</span><strong>开始使用</strong><p>先把入口、角色和建议阅读顺序对齐，避免一上来就在各页之间乱跳。</p></a><a class="link-panel" href="./guide/getting-started.html"><span class="link-panel-label">Quick Start</span><strong>快速开始</strong><p>用最短时间看懂公开入口、当前阶段、CLI 路线和交付主线现在分别是什么。</p></a><a class="link-panel" href="./guide/faq.html"><span class="link-panel-label">FAQ</span><strong>常见问题</strong><p>把定位、隔离、热更新、CLI、本地执行和当前阶段一次讲清楚。</p></a><a class="link-panel" href="./product/"><span class="link-panel-label">Product</span><strong>产品概览</strong><p>先理解平台在做什么，不在做什么，以及当前最准确的公开定义。</p></a><a class="link-panel" href="./product/capabilities.html"><span class="link-panel-label">Capabilities</span><strong>核心能力</strong><p>多租户、可信执行、模板分发、公告治理和 CLI 桥接能力一页看清。</p></a><a class="link-panel" href="./product/cli.html"><span class="link-panel-label">CLI</span><strong>CLI 指引</strong><p>直接看本地登录、脚本注册、Skill 执行和 Agent 骨架目前已经打通到哪一步。</p></a><a class="link-panel" href="./product/customer-flow.html"><span class="link-panel-label">Delivery</span><strong>客户流程 / 交付</strong><p>单独看客户怎么使用平台、平台怎么交付，以及脚本热更新如何形成正式闭环。</p></a><a class="link-panel" href="./materials/"><span class="link-panel-label">Materials</span><strong>对外资料</strong><p>把对外介绍、价值表达和演示提纲单独收成一组公开资料，不再混在产品页里。</p></a></div></section><section class="landing-band landing-band--cta"><div class="cta-card"><div><p class="landing-kicker">Contact</p><h2>现在开放免费线索申请、团队版演示预约和企业版私有化咨询。</h2><p class="landing-lead"> 如果你在做企业交付、自动化平台、本地执行能力接入，或者希望把已有脚本整理成正式产品， 这里就是当前最直接的入口。 </p></div><div class="cta-actions"><a class="cta-button cta-button--brand" href="./contact.html#lead-form">申请免费试用</a><a class="cta-button" href="./contact.html#lead-form">预约团队版演示</a><a class="cta-button" href="https://github.com/zmx2321" target="_blank" rel="noreferrer">查看 GitHub</a></div></div></section></div>',1)]))}const m=n(e,[["render",c]]);export{h as __pageData,m as default};
